// ONBOARDING
// ============================================

model OnboardingProgress {
  id                    String   @id @default(cuid())
  userId                String   @unique
  tenantId              String
  
  // Wizard completion
  wizardCompleted       Boolean  @default(false)
  wizardCompletedAt     DateTime?
  currentStep           Int      @default(1)
  completedSteps        Int[]    @default([])
  skipped               Boolean  @default(false)
  
  // Product tour
  tourCompleted         Boolean  @default(false)
  tourCompletedAt       DateTime?
  tourStep              Int      @default(0)
  
  // Demo mode
  demoModeActive        Boolean  @default(false)
  demoModeActivatedAt   DateTime?
  
  // Progress metrics
  whatsappConnected     Boolean  @default(false)
  firstMessageSent      Boolean  @default(false)
  firstWorkflowCreated  Boolean  @default(false)
  teamMemberInvited     Boolean  @default(false)
  
  // Timestamps
  createdAt             DateTime @default(now())
  updatedAt             DateTime @updatedAt
  
  // Relations
  user                  User     @relation(fields: [userId], references: [id], onDelete: Cascade)
  tenant                Tenant   @relation(fields: [tenantId], references: [id], onDelete: Cascade)
  
  @@index([userId])
  @@index([tenantId])
  @@map("onboarding_progress")
}

// ============================================
// BILLING & SUBSCRIPTIONS
// ============================================

model Subscription {
  id                String   @id @default(cuid())
  tenantId          String   @unique
  
  // Plan details
  tier              TenantPlan @default(FREE)
  status            String   @default("active") // active, past_due, canceled, trialing
  
  // Billing
  billingCycle      String   @default("monthly") // monthly, annual
  currentPeriodStart DateTime?
  currentPeriodEnd   DateTime?
  cancelAtPeriodEnd  Boolean  @default(false)
  
  // Stripe integration
  stripeCustomerId  String?  @unique
  stripeSubscriptionId String? @unique
  stripePriceId     String?
  
  // Usage tracking
  messagesUsed      Int      @default(0)
  contactsUsed      Int      @default(0)
  workflowsUsed     Int      @default(0)
  teamMembersUsed   Int      @default(0)
  
  // Limits (based on tier)
  messagesLimit     Int      @default(100)
  contactsLimit     Int      @default(50)
  workflowsLimit    Int      @default(3)
  teamMembersLimit  Int      @default(1)
  
  // Timestamps
  createdAt         DateTime @default(now())
  updatedAt         DateTime @updatedAt
  trialEndsAt       DateTime?
  canceledAt        DateTime?
  
  // Relations
  tenant            Tenant   @relation(fields: [tenantId], references: [id], onDelete: Cascade)
  usageRecords      UsageRecord[]
  
  @@index([tenantId])
  @@index([status])
  @@index([stripeCustomerId])
  @@map("subscriptions")
}

model Invoice {
  id              String   @id @default(cuid())
  tenantId        String
  invoiceNumber   String   @unique
  
  // Billing details
  amount          Float
  currency        String   @default("usd")
  status          String   @default("pending") // pending, paid, failed, refunded
  
  // Stripe integration
  stripeInvoiceId String?  @unique
  
  // Invoice details
  billingName     String?
  billingEmail    String?
  billingAddress  Json?
  lineItems       Json     @default("[]")
  taxAmount       Float    @default(0)
  
  // Timestamps
  paidAt          DateTime?
  dueAt           DateTime?
  createdAt       DateTime @default(now())
  updatedAt       DateTime @updatedAt
  
  // Metadata
  metadata        Json     @default("{}")
  
  // Relations
  tenant          Tenant   @relation(fields: [tenantId], references: [id], onDelete: Cascade)

  @@index([tenantId])
  @@index([status])
  @@index([invoiceNumber])
  @@map("invoices")
}

model UsageRecord {
  id             String   @id @default(cuid())
  subscriptionId String
  tenantId       String
  
  // Resource type
  resourceType   String   // messages, contacts, workflows, team_members
  
  // Usage data
  quantity       Int
  timestamp      DateTime @default(now())
  
  // Metadata
  metadata       Json     @default("{}")
  
  // Relations
  subscription   Subscription @relation(fields: [subscriptionId], references: [id], onDelete: Cascade)
  
  @@index([subscriptionId, timestamp])
  @@index([tenantId, resourceType, timestamp])
  @@map("usage_records")
}

// ============================================
// SUPPORT SYSTEM
// ============================================

model SupportTicket {
  id                    String   @id @default(cuid())
  ticketNumber          String   @unique
  
  // User info
  userId                String
  tenantId              String
  
  // Ticket details
  category              String   // technical_issue, billing_question, feature_request, account_management, whatsapp_connection, other
  priority              String   @default("medium") // low, medium, high, urgent
  status                String   @default("open") // open, in_progress, waiting_on_customer, resolved, closed
  subject               String
  description           String   @db.Text
  
  // Assignment
  assignedTo            String?
  
  // Timestamps
  createdAt             DateTime @default(now())
  updatedAt             DateTime @updatedAt
  resolvedAt            DateTime?
  closedAt              DateTime?
  
  // Relations
  user                  User     @relation(fields: [userId], references: [id], onDelete: Cascade)
  tenant                Tenant   @relation(fields: [tenantId], references: [id], onDelete: Cascade)
  messages              TicketMessage[]
  attachments           TicketAttachment[]
  
  @@index([userId])
  @@index([tenantId])
  @@index([ticketNumber])
  @@index([status])
  @@index([category])
  @@map("support_tickets")
}

model TicketMessage {
  id                    String   @id @default(cuid())
  ticketId              String
  
  // Message details
  senderId              String
  senderType            String   // user, agent
  content               String   @db.Text
  
  // Timestamps
  createdAt             DateTime @default(now())
  
  // Relations
  ticket                SupportTicket @relation(fields: [ticketId], references: [id], onDelete: Cascade)
  attachments           TicketAttachment[]
  
  @@index([ticketId, createdAt])
  @@map("ticket_messages")
}

model TicketAttachment {
  id                    String   @id @default(cuid())
  ticketId              String
  messageId             String?
  
  // File details
  filename              String
  url                   String
  size                  Int
  mimeType              String
  
  // Timestamps
  createdAt             DateTime @default(now())
  
  // Relations
  ticket                SupportTicket @relation(fields: [ticketId], references: [id], onDelete: Cascade)
  message               TicketMessage? @relation(fields: [messageId], references: [id], onDelete: Cascade)
  
  @@index([ticketId])
  @@index([messageId])
  @@map("ticket_attachments")
}

// ============================================
// HELP CENTER
// ============================================

model HelpArticle {
  id                    String   @id @default(cuid())
  
  // Article details
  title                 String
  slug                  String   @unique
  content               String   @db.Text
  excerpt               String?
  
  // Organization
  categoryId            String
  categoryName          String
  tags                  String[] @default([])
  
  // Metadata
  author                String?
  publishedAt           DateTime?
  updatedAt             DateTime @updatedAt
  createdAt             DateTime @default(now())
  
  // Analytics
  views                 Int      @default(0)
  helpfulCount          Int      @default(0)
  notHelpfulCount       Int      @default(0)
  
  // Related content
  relatedArticleIds     String[] @default([])
  videoUrl              String?
  
  // Status
  isPublished           Boolean  @default(false)
  
  @@index([slug])
  @@index([categoryId])
  @@index([isPublished])
  @@map("help_articles")
}

model FAQ {
  id                    String   @id @default(cuid())
  
  // FAQ details
  question              String
  answer                String   @db.Text
  
  // Organization
  category              String   // getting_started, billing, whatsapp_connection, features, troubleshooting
  order                 Int      @default(0)
  
  // Analytics
  helpfulCount          Int      @default(0)
  notHelpfulCount       Int      @default(0)
  views                 Int      @default(0)
  
  // Timestamps
  createdAt             DateTime @default(now())
  updatedAt             DateTime @updatedAt
  
  // Status
  isPublished           Boolean  @default(true)
  
  @@index([category, order])
  @@index([isPublished])
  @@map("faqs")
}

model VideoTutorial {
  id                    String   @id @default(cuid())
  
  // Video details
  title                 String
  description           String   @db.Text
  youtubeId             String
  thumbnail             String?
  duration              Int      // seconds
  
  // Organization
  category              String
  tags                  String[] @default([])
  
  // Analytics
  views                 Int      @default(0)
  
  // Transcript
  transcript            String?  @db.Text
  
  // Timestamps
  publishedAt           DateTime?
  createdAt             DateTime @default(now())
  updatedAt             DateTime @updatedAt
  
  // Status
  isPublished           Boolean  @default(true)
  
  @@index([category])
  @@index([isPublished])
  @@map("video_tutorials")
}

