import { prisma } from "../../lib/prisma";
import { logger } from "../../lib/logger";

export class OnboardingService {
  /**
   * Get current onboarding status for a user
   */
  async getStatus(userId: string, tenantId: string) {
    let progress = await prisma.onboardingProgress.findUnique({
      where: { userId },
    });

    // Create initial progress record if it doesn't exist
    if (!progress) {
      progress = await prisma.onboardingProgress.create({
        data: {
          userId,
          tenantId,
        },
      });
    }

    return progress;
  }

  /**
   * Mark a specific step as complete
   */
  async completeStep(userId: string, stepNumber: number) {
    const progress = await prisma.onboardingProgress.findUnique({
      where: { userId },
    });

    if (!progress) {
      throw Object.assign(new Error("Onboarding progress not found"), { statusCode: 404 });
    }

    // Validate step number (1-5)
    if (stepNumber < 1 || stepNumber > 5) {
      throw Object.assign(new Error("Invalid step number. Must be between 1 and 5"), { statusCode: 400 });
    }

    // Add step to completed steps if not already there
    const completedSteps = progress.completedSteps.includes(stepNumber)
      ? progress.completedSteps
      : [...progress.completedSteps, stepNumber].sort();

    // Check if all steps are completed
    const allStepsCompleted = completedSteps.length === 5 && 
      completedSteps.every((step, index) => step === index + 1);

    // Update progress
    const updated = await prisma.onboardingProgress.update({
      where: { userId },
      data: {
        completedSteps,
        currentStep: Math.min(stepNumber + 1, 5),
        wizardCompleted: allStepsCompleted,
        wizardCompletedAt: allStepsCompleted ? new Date() : progress.wizardCompletedAt,
      },
    });

    logger.info("Onboarding step completed", { userId, stepNumber, allStepsCompleted });

    return updated;
  }

  /**
   * Skip the onboarding wizard
   */
  async skipWizard(userId: string) {
    const progress = await prisma.onboardingProgress.findUnique({
      where: { userId },
    });

    if (!progress) {
      throw Object.assign(new Error("Onboarding progress not found"), { statusCode: 404 });
    }

    const updated = await prisma.onboardingProgress.update({
      where: { userId },
      data: {
        skipped: true,
        wizardCompleted: true,
        wizardCompletedAt: new Date(),
      },
    });

    logger.info("Onboarding wizard skipped", { userId });

    return updated;
  }

  /**
   * Resume incomplete onboarding
   */
  async resumeOnboarding(userId: string) {
    const progress = await prisma.onboardingProgress.findUnique({
      where: { userId },
    });

    if (!progress) {
      throw Object.assign(new Error("Onboarding progress not found"), { statusCode: 404 });
    }

    // Reset skipped flag to allow resuming
    const updated = await prisma.onboardingProgress.update({
      where: { userId },
      data: {
        skipped: false,
        wizardCompleted: false,
        wizardCompletedAt: null,
      },
    });

    logger.info("Onboarding resumed", { userId });

    return updated;
  }

  /**
   * Record product tour completion
   */
  async completeTour(userId: string) {
    const progress = await prisma.onboardingProgress.findUnique({
      where: { userId },
    });

    if (!progress) {
      throw Object.assign(new Error("Onboarding progress not found"), { statusCode: 404 });
    }

    const updated = await prisma.onboardingProgress.update({
      where: { userId },
      data: {
        tourCompleted: true,
        tourCompletedAt: new Date(),
      },
    });

    logger.info("Product tour completed", { userId });

    return updated;
  }

  /**
   * Get tour completion status
   */
  async getTourStatus(userId: string) {
    const progress = await prisma.onboardingProgress.findUnique({
      where: { userId },
      select: {
        tourCompleted: true,
        tourCompletedAt: true,
        tourStep: true,
      },
    });

    if (!progress) {
      return {
        tourCompleted: false,
        tourCompletedAt: null,
        tourStep: 0,
      };
    }

    return progress;
  }

  /**
   * Get detailed progress breakdown including all metrics
   */
  async getProgress(userId: string, tenantId: string) {
    const progress = await this.getStatus(userId, tenantId);

    // Calculate overall completion percentage
    let completionPercentage = 0;

    // Wizard completion: 25%
    if (progress.wizardCompleted) {
      completionPercentage += 25;
    }

    // WhatsApp connected: 25%
    if (progress.whatsappConnected) {
      completionPercentage += 25;
    }

    // First message sent: 25%
    if (progress.firstMessageSent) {
      completionPercentage += 25;
    }

    // First workflow created: 15%
    if (progress.firstWorkflowCreated) {
      completionPercentage += 15;
    }

    // Team member invited: 10%
    if (progress.teamMemberInvited) {
      completionPercentage += 10;
    }

    // Determine suggested next steps
    const suggestedNextSteps: string[] = [];

    if (!progress.wizardCompleted && !progress.skipped) {
      suggestedNextSteps.push("Complete the onboarding wizard");
    }

    if (!progress.whatsappConnected) {
      suggestedNextSteps.push("Connect your WhatsApp account");
    }

    if (progress.whatsappConnected && !progress.firstMessageSent) {
      suggestedNextSteps.push("Send your first test message");
    }

    if (!progress.firstWorkflowCreated) {
      suggestedNextSteps.push("Create your first automation workflow");
    }

    if (!progress.teamMemberInvited) {
      suggestedNextSteps.push("Invite a team member to collaborate");
    }

    return {
      ...progress,
      completionPercentage,
      suggestedNextSteps,
      isComplete: completionPercentage === 100,
    };
  }

  /**
   * Update progress metrics (called by other services)
   */
  async updateMetric(
    userId: string,
    metric: "whatsappConnected" | "firstMessageSent" | "firstWorkflowCreated" | "teamMemberInvited",
    value: boolean = true
  ) {
    const progress = await prisma.onboardingProgress.findUnique({
      where: { userId },
    });

    if (!progress) {
      logger.warn("Attempted to update metric for non-existent onboarding progress", { userId, metric });
      return null;
    }

    const updated = await prisma.onboardingProgress.update({
      where: { userId },
      data: {
        [metric]: value,
      },
    });

    logger.info("Onboarding metric updated", { userId, metric, value });

    return updated;
  }
}

import { Hono } from "hono";
import { OnboardingService } from "./service";
import { authMiddleware } from "../../middleware/auth";

export const onboardingRoutes = new Hono();

const onboardingService = new OnboardingService();

// Apply auth middleware to all routes
onboardingRoutes.use("*", authMiddleware);

// GET /onboarding/status - Get current onboarding progress
onboardingRoutes.get("/status", async (c) => {
  const userId = c.get("userId");
  const tenantId = c.get("tenantId");
  const status = await onboardingService.getStatus(userId, tenantId);
  return c.json({ success: true, data: status });
});

// POST /onboarding/step/:stepNumber/complete - Mark step as complete
onboardingRoutes.post("/step/:stepNumber/complete", async (c) => {
  const userId = c.get("userId");
  const stepNumber = parseInt(c.req.param("stepNumber"));

  if (isNaN(stepNumber)) {
    return c.json({ success: false, error: "Invalid step number" }, 400);
  }

  const progress = await onboardingService.completeStep(userId, stepNumber);
  return c.json({ success: true, data: progress });
});

// POST /onboarding/skip - Skip the onboarding wizard
onboardingRoutes.post("/skip", async (c) => {
  const userId = c.get("userId");
  const progress = await onboardingService.skipWizard(userId);
  return c.json({ success: true, data: progress, message: "Onboarding wizard skipped" });
});

// POST /onboarding/resume - Resume incomplete onboarding
onboardingRoutes.post("/resume", async (c) => {
  const userId = c.get("userId");
  const progress = await onboardingService.resumeOnboarding(userId);
  return c.json({ success: true, data: progress, message: "Onboarding resumed" });
});

// POST /onboarding/tour/complete - Record tour completion
onboardingRoutes.post("/tour/complete", async (c) => {
  const userId = c.get("userId");
  const progress = await onboardingService.completeTour(userId);
  return c.json({ success: true, data: progress, message: "Product tour completed" });
});

// GET /onboarding/tour/status - Check tour status
onboardingRoutes.get("/tour/status", async (c) => {
  const userId = c.get("userId");
  const status = await onboardingService.getTourStatus(userId);
  return c.json({ success: true, data: status });
});

// GET /onboarding/progress - Get detailed progress breakdown
onboardingRoutes.get("/progress", async (c) => {
  const userId = c.get("userId");
  const tenantId = c.get("tenantId");
  const progress = await onboardingService.getProgress(userId, tenantId);
  return c.json({ success: true, data: progress });
});

